// Generated by OrchestKit Claude Plugin
// Created: 2026-05-13

/**
 * Deferred worktree-advisory delivery (#1794 follow-up — PR-2).
 *
 * Background: PR-1 (#1797) replaced the wrong-envelope return in
 * worktree-lifecycle-logger.ts with `outputSilentSuccess()` because CC does
 * not consume `additionalContext` on `WorktreeCreate` events. That fixed the
 * literal-named-directory bug, but it also silenced the monorepo `sparsePaths`
 * advisory — it now only reaches `ctx.log()` (dev-facing), not the model.
 *
 * This module reintroduces model-facing delivery via a deferred mechanism:
 *
 *   1. `writeWorktreeAdvisory` (called from WorktreeCreate hook) writes the
 *      advisory to `.claude/state/worktree-advisory-<slug>.<sid>.md`, keyed
 *      by the CREATING session so another concurrent session cannot
 *      consume-and-destroy it (#2919). Idempotent: writing twice with the
 *      same name+session just overwrites.
 *
 *   2. `consumeWorktreeAdvisories` (called from UserPromptSubmit hook) reads
 *      the pending advisory files OWNED BY THIS SESSION (plus legacy
 *      un-keyed files, so pre-upgrade advisories still deliver instead of
 *      orphaning), concatenates them, deletes them, returns the joined
 *      text. Returns `null` if nothing pending — caller emits silent
 *      success.
 *
 * This way the next user prompt after a worktree create receives the
 * `sparsePaths` nudge as `additionalContext` — which CC DOES consume on
 * UserPromptSubmit.
 *
 * File format: plain Markdown. No frontmatter. One advisory per file so
 * partial cleanup is straightforward if the consumer dies mid-read.
 */

import { existsSync, mkdirSync, readFileSync, readdirSync, unlinkSync, writeFileSync } from 'node:fs';
import { join } from 'node:path';

/** Where pending advisories live, relative to projectDir. */
const ADVISORY_DIR = join('.claude', 'state');

/** Prefix that identifies an advisory file. Anything else in state/ is left alone. */
const ADVISORY_PREFIX = 'worktree-advisory-';

/** Suffix for advisory files. Stays consistent with project conventions for state files. */
const ADVISORY_SUFFIX = '.md';

/**
 * Sanitize a worktree name to a safe filesystem slug.
 * Allowed: a-z, A-Z, 0-9, dash, underscore. Anything else becomes a dash.
 * Empty input falls back to 'unknown' to avoid landing in a hidden file.
 */
export function slugify(name: string): string {
  if (!name) return 'unknown';
  const cleaned = name.replace(/[^a-zA-Z0-9_-]/g, '-').replace(/-+/g, '-').replace(/^-|-$/g, '');
  return cleaned.length > 0 ? cleaned : 'unknown';
}

/**
 * Write a pending advisory to be consumed on the next UserPromptSubmit.
 *
 * Best-effort: any I/O error is swallowed (hook must not throw / block CC).
 * Returns true on successful write, false on any failure — caller logs.
 */
export function writeWorktreeAdvisory(
  advisory: string,
  name: string,
  projectDir: string,
  sessionId?: string,
): boolean {
  if (!advisory?.trim() || !projectDir) return false;
  try {
    const dir = join(projectDir, ADVISORY_DIR);
    mkdirSync(dir, { recursive: true });
    // Session key goes in the filename (dot-separated — slugs can't contain
    // dots) so the consumer can filter without opening the file.
    const sidPart = sessionId ? `.${slugify(sessionId)}` : '';
    const file = join(dir, `${ADVISORY_PREFIX}${slugify(name)}${sidPart}${ADVISORY_SUFFIX}`);
    writeFileSync(file, `${advisory.trimEnd()}\n`, 'utf8');
    return true;
  } catch {
    return false;
  }
}

/**
 * True when the advisory filename belongs to `sessionId` — or is a legacy
 * un-keyed file (no dot-separated session segment), which any session may
 * deliver so pre-upgrade advisories don't orphan.
 */
function advisoryBelongsTo(fileName: string, sessionId: string): boolean {
  const base = fileName.slice(ADVISORY_PREFIX.length, -ADVISORY_SUFFIX.length);
  const dotIdx = base.lastIndexOf('.');
  if (dotIdx === -1) return true; // legacy format: worktree-advisory-<slug>.md
  return base.slice(dotIdx + 1) === slugify(sessionId);
}

/**
 * Read and delete all pending advisory files. Returns concatenated content
 * joined by blank lines, or `null` if nothing pending.
 *
 * Deletion happens AFTER successful read of each file. If reading one file
 * throws (e.g. EBUSY), the others are still processed and returned —
 * partial-results semantics so a single bad file doesn't suppress the rest.
 */
export function consumeWorktreeAdvisories(projectDir: string, sessionId = ''): string | null {
  if (!projectDir) return null;
  const dir = join(projectDir, ADVISORY_DIR);
  if (!existsSync(dir)) return null;

  let entries: string[];
  try {
    entries = readdirSync(dir);
  } catch {
    return null;
  }

  const advisoryFiles = entries
    .filter(name => name.startsWith(ADVISORY_PREFIX) && name.endsWith(ADVISORY_SUFFIX))
    .filter(name => advisoryBelongsTo(name, sessionId))
    .sort();

  if (advisoryFiles.length === 0) return null;

  const collected: string[] = [];
  for (const file of advisoryFiles) {
    const fullPath = join(dir, file);
    try {
      const content = readFileSync(fullPath, 'utf8').trimEnd();
      if (content.length > 0) collected.push(content);
      // Delete only after successful read — keeps file as fallback if read failed
      try { unlinkSync(fullPath); } catch { /* best-effort cleanup */ }
    } catch {
      // Skip this file on read error; leave it on disk for the next prompt.
    }
  }

  return collected.length > 0 ? collected.join('\n\n---\n\n') : null;
}
